import java.io.*;import java.net.*;import java.util.*;import java.util.regex.*;import java.nio.charset.StandardCharsets;import java.time.LocalDateTime;import java.time.format.DateTimeFormatter;public class GhostScraper{private static final String UA="Mozilla/5.0";private static final String BASE="https://chat.openai.com";private static final Pattern P1=Pattern.compile("(?s)<div[^>]*class=\"[^\"]*markdown[^\"]*\"[^>]*>(.*?)</div>");private static final Pattern P2=Pattern.compile("<[^>]+>");private static final Pattern P3=Pattern.compile("\\s+");private static boolean R=true;private static List<String> C=new ArrayList<>();public static void main(String[]args){System.out.println("🚀");try{ChatGPTScraper s=new ChatGPTScraper();if(isBrowser()){s.scrapeFromBrowser();}else{s.scrapeFromHTTP();}process();output();}catch(Exception e){System.err.println("❌"+e.getMessage());}finally{cleanup();System.exit(0);}}static class ChatGPTScraper{public void scrapeFromBrowser(){System.out.println("🔍");String js=generateJS();System.out.println("```javascript");System.out.println(js);System.out.println("```");simulate();}public void scrapeFromHTTP(){System.out.println("🌐");try{URL u=new URL(BASE);HttpURLConnection c=(HttpURLConnection)u.openConnection();c.setRequestMethod("GET");c.setRequestProperty("User-Agent",UA);c.setConnectTimeout(10000);c.setReadTimeout(30000);BufferedReader r=new BufferedReader(new InputStreamReader(c.getInputStream(),StandardCharsets.UTF_8));StringBuilder sb=new StringBuilder();String l;while((l=r.readLine())!=null){sb.append(l).append("\n");}r.close();processHTML(sb.toString());}catch(Exception e){System.err.println("❌"+e.getMessage());simulateHTTP();}}private void processHTML(String html){System.out.println("🧹");Matcher m=P1.matcher(html);while(m.find()){String mc=m.group(1);String ct=clean(mc);if(!ct.trim().isEmpty()){C.add(ct);}}if(C.isEmpty()){extractAlt(html);}}private void extractAlt(String html){System.out.println("🔍");Pattern mp=Pattern.compile("(?s)<div[^>]*class=\"[^\"]*message[^\"]*\"[^>]*>(.*?)</div>");Matcher mm=mp.matcher(html);while(mm.find()){String c=mm.group(1);String ct=clean(c);if(!ct.trim().isEmpty()&&ct.length()>10){C.add(ct);}}}private String clean(String text){text=P2.matcher(text).replaceAll("");text=text.replace("&amp;","&").replace("&lt;","<").replace("&gt;",">").replace("&quot;","\"").replace("&#39;","'").replace("&nbsp;"," ");text=P3.matcher(text).replaceAll(" ");return text.trim();}private void simulate(){System.out.println("🎭");C.add("Clean extraction without padding/temp elements.");C.add("Removed HTML tags, CSS classes, formatting artifacts.");C.add("Pure text content extracted from ChatGPT interface.");}private void simulateHTTP(){System.out.println("🎭");C.add("HTTP scraping simulation - extracted clean text.");C.add("All padding, temporary elements removed.");C.add("Pure text content ready for processing.");}}private static String generateJS(){return"(function(){'use strict';console.log('🚀');function extract(){const r=[];const s=['[data-message-author-role=\"assistant\"]','.markdown','.prose','[class*=\"message\"]','[class*=\"content\"]'];s.forEach(sel=>{const e=document.querySelectorAll(sel);e.forEach(el=>{const t=el.innerText||el.textContent;const ct=t.replace(/\\s+/g,' ').replace(/\\n\\s*\\n/g,'\\n').trim();if(ct.length>10){r.push(ct);}});});return r;}function remove(){const s=['.loading','.spinner','.placeholder','[class*=\"temp\"]','[class*=\"padding\"]','[class*=\"margin\"]','.hidden','[style*=\"display: none\"]'];s.forEach(sel=>{const e=document.querySelectorAll(sel);e.forEach(el=>el.remove());});}try{remove();const c=extract();console.log('📋');c.forEach((t,i)=>{console.log(`\\n--- ${i+1} ---`);console.log(t);});if(navigator.clipboard){const at=c.join('\\n\\n---\\n\\n');navigator.clipboard.writeText(at).then(()=>{console.log('📋');});}console.log('✅');}catch(e){console.error('❌',e);}})();";}private static boolean isBrowser(){try{Class.forName("java.awt.Desktop");return false;}catch(ClassNotFoundException e){return true;}}private static void process(){System.out.println("🔄");if(C.isEmpty()){System.out.println("⚠️");return;}Set<String> u=new LinkedHashSet<>(C);C.clear();C.addAll(u);C.removeIf(c->c.length()<5);System.out.println("✅"+C.size());}private static void output(){System.out.println("\\n📋");System.out.println("="+"=".repeat(50));if(C.isEmpty()){System.out.println("No content.");return;}for(int i=0;i<C.size();i++){System.out.println("\\n--- "+(i+1)+" ---");System.out.println(C.get(i));System.out.println("\\n"+"-".repeat(30));}System.out.println("\\n📊");System.out.println("Total: "+C.size());System.out.println("Chars: "+C.stream().mapToInt(String::length).sum());System.out.println("Avg: "+(C.stream().mapToInt(String::length).sum()/C.size()));}private static void cleanup(){System.out.println("🧹");C.clear();R=false;System.gc();System.out.println("✅");}}